  ]
}

{
  "intent": "check_and_fix",
  "intent_description": "Restore operational serial link between router1 Serial0/1/0 and router2 Serial0/1/0 after router2 admin-down and router1 lower-layer-down; expected outcome is oper_state=up on affected interfaces.",
