  "needs_fix": true,
  "plan": {
    "problem": "Serial link down: router2 Serial0/1/0 is administratively down (oper down); router1 Serial0/1/0 is admin up but oper lower-layer-down (possible clocking/line-rate mismatch).",
    "fix_summary": "Re-enable router2 interface administratively. If the link remains down, align clocking/line-rate on router1 Serial0/1/0 to match router2 (2048000 bps).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/0",
